(()=>{'use strict';
const T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0,F=n=>N(n).toLocaleString('th-TH'),B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const sorter=new Intl.Collator('th-u-kn-true',{numeric:true,sensitivity:'base'});let rows=[],meta={},lastPayload=null;
function $(s){return document.querySelector(s)}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function realTele(r){const tele=T(r.tele),ps=T(r.ps);if(!tele)return false;const kt=norm(tele),kp=norm(ps);if(kt&&kp&&(kt===kp||kp.includes(kt)||kt.includes(kp)))return false;return !!(r.isTele||tele)}
function datestr(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function filters(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value),receiver:T($('#storeSelect')?.value),brand:T($('#brandSelect')?.value),type:T($('#typeSelect')?.value),q:T($('#q')?.value).toLowerCase()}}
function stateKey(){return 'doit-json:'+(meta.id||lastPayload?.version_id||meta.file_name||'')}
function state(){try{return JSON.parse(localStorage.getItem(stateKey())||'{}')}catch{return{}}}
function pk(r){return [r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}
function baseRows(visible=true){const f=filters();return rows.filter(r=>!realTele(r)&&(!f.start||r.date>=f.start)&&(!f.end||r.date<=f.end)&&(!f.ps||r.ps===f.ps)&&(!visible||!f.brand||r.brand===f.brand)&&(!visible||!f.type||r.type===f.type)&&(!visible||!f.q||[r.date,r.inv,r.code,r.sku,r.store,r.ps,r.brand,r.size,r.type].join(' ').toLowerCase().includes(f.q)))}
function group(visible=true){const m=new Map();baseRows(visible).forEach(r=>{const k=pk(r);let g=m.get(k);if(!g){g={poolKey:k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0,bills:new Set(),stores:new Set()};m.set(k,g)}g.qty+=N(r.qty);g.amt+=N(r.amt);g.unit=g.qty&&g.amt?g.amt/g.qty:g.unit;g.bills.add(r.inv);g.stores.add(r.store)});return [...m.values()].sort((a,b)=>sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code||'',b.code||'')||sorter.compare(a.sku,b.sku)||sorter.compare(a.type,b.type))}
function recFromKey(k){return String(k).split('|')[3]||''}
function pkFromKey(k){return String(k).split('|').slice(4).join('|')}
function scopeHead(){const f=filters();return[f.start,f.end,f.ps].join('|')+'|'}
function deliveryLines(){const f=filters(),st=state(),send=st.send||{},gmap=new Map(group(false).map(g=>[g.poolKey,g])),out=[];Object.keys(send).filter(k=>k.startsWith(scopeHead())).forEach(k=>{const q=N(send[k]);if(q<=0)return;const g=gmap.get(pkFromKey(k));const rec=recFromKey(k);if(g&&rec)out.push({store:rec,code:g.code||'',name:g.sku,brand:g.brand,size:g.size,type:g.type,qty:q,unit:g.unit||0})});return out.sort((a,b)=>sorter.compare(a.store,b.store)||sorter.compare(a.brand,b.brand)||sorter.compare(a.size,b.size)||sorter.compare(a.code,b.code)||sorter.compare(a.name,b.name))}
function exportCsv(e){e?.preventDefault?.();e?.stopImmediatePropagation?.();const out=[['ชื่อรายการ','จำนวน']];group(true).forEach(g=>out.push([g.sku,g.qty]));if(out.length===1){alert('ไม่พบข้อมูลในตารางตามตัวกรองปัจจุบัน');return}const csv='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));a.download='doit-pick-list-name-qty.csv';a.click()}
function printForm(e){e?.preventDefault?.();e?.stopImmediatePropagation?.();const data=deliveryLines();if(!data.length){alert('ยังไม่ได้ใส่จำนวนส่งจริงให้ร้านใด');return}const by={};data.forEach(l=>(by[l.store]??=[]).push(l));const w=window.open('','_blank');if(!w){alert('เบราว์เซอร์บล็อกหน้าปริ้น');return}const d=w.document;d.body.innerHTML='';d.title='แบบฟอร์มใบส่งสินค้า';const style=d.createElement('style');style.textContent='@page{size:A4;margin:8mm}body{font-family:Tahoma,Arial,sans-serif;margin:0;background:#eee}.bar{position:sticky;top:0;background:#087b34;color:white;padding:10px}.bar button{font-weight:900;padding:8px 14px}.page{background:white;width:194mm;min-height:281mm;margin:10px auto;padding:8mm;page-break-after:always}.head{display:flex;justify-content:space-between;border-bottom:2px solid #111;margin-bottom:8px;padding-bottom:6px}.shop{font-size:16px;font-weight:900}table{width:100%;border-collapse:collapse;font-size:12px}th,td{border:1px solid #111;padding:4px}th{background:#eee}.r{text-align:right}.price{width:75px;text-align:right}.sign{display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;margin-top:24px;text-align:center}.sign div{border-top:1px solid #111;padding-top:6px}@media print{body{background:white}.bar{display:none}.page{margin:0}.price{border:0}}';d.head.appendChild(style);const bar=d.createElement('div');bar.className='bar';bar.innerHTML='<b>แก้ราคา/หน่วยก่อน แล้วค่อยกดสั่งปริ้น</b> ';const btn=d.createElement('button');btn.textContent='สั่งปริ้น';bar.appendChild(btn);d.body.appendChild(bar);const f=filters();Object.entries(by).forEach(([store,items],bi)=>{const pg=d.createElement('section');pg.className='page';pg.innerHTML=`<div class="head"><div><b>ใบส่งสินค้า</b><div class="shop">ร้าน: ${esc(store)}</div></div><div>วันที่: ${esc(datestr(f.end||f.start))}<br>PS: ${esc(f.ps||'ทั้งหมด')}<br>ใบที่: ${bi+1}</div></div><table><thead><tr><th>#</th><th>รหัส</th><th>รายการ</th><th>จำนวน</th><th>ราคา/หน่วย</th><th>รวม</th></tr></thead><tbody></tbody></table><div class="sign"><div>ผู้จัดของ</div><div>ผู้ส่ง</div><div>ผู้รับสินค้า</div></div>`;const tb=pg.querySelector('tbody');items.forEach((l,i)=>{const tr=d.createElement('tr');tr.innerHTML=`<td>${i+1}</td><td>${esc(l.code)}</td><td>${esc(l.name)}<br><small>${esc(l.brand)} · ${esc(l.size)} · ${esc(l.type)}</small></td><td class="r">${F(l.qty)}</td><td class="r"></td><td class="r total">0.00</td>`;const inp=d.createElement('input');inp.className='price';inp.type='number';inp.step='0.01';inp.value=String(Math.round(N(l.unit)*100)/100);inp.dataset.qty=l.qty;tr.children[4].appendChild(inp);tb.appendChild(tr)});tb.insertAdjacentHTML('beforeend','<tr><td colspan="5" class="r"><b>รวม</b></td><td class="r billTotal">0.00</td></tr>');d.body.appendChild(pg)});function recalc(){d.querySelectorAll('.page').forEach(pg=>{let sum=0;pg.querySelectorAll('.price').forEach(inp=>{const v=N(inp.value)*N(inp.dataset.qty);sum+=v;inp.closest('tr').querySelector('.total').textContent=B(v)});pg.querySelector('.billTotal').textContent=B(sum)})}d.querySelectorAll('.price').forEach(i=>i.oninput=recalc);btn.onclick=()=>{recalc();w.print()};recalc()}
function guardRedo(e){try{document.querySelector('#redo')?.onclick?.call(document.querySelector('#redo'),e)}catch(err){e?.preventDefault?.();e?.stopImmediatePropagation?.();alert('Redo มีปัญหาจาก cache เก่า ให้รีเฟรชหน้าแล้วลองใหม่')}}
function installButtons(){const p=$('#prepPrint'),x=$('#exportCsv'),r=$('#redo');if(p&&!p.dataset.fix267){p.dataset.fix267='1';p.addEventListener('click',printForm,true)}if(x&&!x.dataset.fix267){x.dataset.fix267='1';x.addEventListener('click',exportCsv,true)}if(r&&!r.dataset.fix267){r.dataset.fix267='1';r.addEventListener('click',guardRedo,true)}}
function wrap(){if(!window.DOIT_JSON_APP||window.DOIT_JSON_APP.__printFix267)return false;const app=window.DOIT_JSON_APP,old=app.load.bind(app);app.load=(payload,m={})=>{lastPayload=payload;meta=m||{};const all=(payload.rows||payload||[]).map(r=>({date:T(r.date),inv:T(r.inv),store:T(r.store),tele:T(r.tele),isTele:!!r.isTele,ps:T(r.ps),code:T(r.code),sku:T(r.sku),brand:T(r.brand),size:T(r.size),type:T(r.type)||'INVC',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}));rows=all;const filtered=all.filter(r=>!realTele(r));const next=Array.isArray(payload)?filtered:{...payload,rows:filtered};old(next,m);setTimeout(()=>{installButtons();window.DOIT_TELESALE_DRAWER?.loadRows(all,{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value)})},80)};app.__printFix267=true;return true}
function boot(){installButtons();if(!wrap())setTimeout(boot,300)}document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();})();